        let a: Sdr = [0xFF, 0xF0, 0, 0]; // 12 bits set
        let b: Sdr = [0x0F, 0xFF, 0, 0]; // 12 bits set
        let va = to_bipolar_f32(&a);
        let vb = to_bipolar_f32(&b);
        let dot: f32 = va.iter().zip(vb.iter()).map(|(x, y)| x * y).sum();
        let hamming = hamming_distance(&a, &b);
