        let mut embedding = vec![0.0f32; SDR_BITS];
        // Set first 8 dims positive, rest negative
        for i in 0..8 {
            embedding[i] = 1.0;
        }
        for i in 8..SDR_BITS {
            embedding[i] = -1.0;
        }
        // 0.0 is treated as positive (>= 0.0)
        let sdr = binarize(&embedding);
        // First 8 bits should be set in word 0
        assert_eq!(sdr[0] & 0xFF, 0xFF);
    }

